  ('cpa-moex-00857', 'cpa', 'cpa-moex-107-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲公司的總公司設在臺北市，另在日本設有分公司，106年度總公司的營利事業課稅所得額為新 臺幣100萬元，日本分公司的課稅所得額以新臺幣計算為50萬元，繳納該國所得稅以新臺幣計 算為20萬元，已提出日本稅務機關發給之同一年度納稅憑證，並取得我國認許機構之簽證，則 甲公司於申報該年度營利事業所得稅時，可列報國外已納稅款之扣抵數額為新臺幣多少元？', '["25萬元", "20萬元", "8.5萬元", "10萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:11+00:00", "source_pdf_sha1": "8ab58f7eb7b2", "answer_pdf_sha1": "ee8510c81af0", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
